#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = new CGI;
my $logfile = $cgi->param('logfile');

# Define allowed directories
my @allowed_dirs = qw(/var/log /home/logs);

# Prevent path traversal
if ($logfile =~ m/\/\.\.\/|\.\/|..\/) {
    print "Content-type: text/plain\n\n";
    print "Error: Path Traversal Attempted\n";
    exit;
}

# Define log directory
my $log_dir = '/var/log'; # Change this to your desired log directory

# Get filename from query parameter
my ($filename) = $logfile =~ m/([^\/]+)$/;
$filename .= '.log' unless $filename =~ m/\.(log|txt)$/;

# Open file and read content
open(my $FH, "<:encoding(utf8)", "$log_dir/$filename") or die "Error opening file: $!";
my @lines;
while (my $line = <$FH>) {
    push(@lines, $line);
}
close($FH);

# Display log content
print "Content-type: text/plain\n\n";
foreach my $line (@lines) {
    print "$line";
}